import datetime

def is_beautiful_date(date_str):
    return len(set(date_str)) == 6

def generate_dates(year):
    dates = []
    for month in range(1, 13):
        for day in range(1, 32):
            try:
                date = datetime.date(year, month, day)
                date_str = date.strftime('%d.%m.%y')
                if is_beautiful_date(date_str):
                    dates.append(date_str)
            except ValueError:
                continue
    return dates

beautiful_dates = generate_dates(2023)
print(len(beautiful_dates))
```

This code will generate all possible dates in the year 2023, check if each date is beautiful, and then print the number of beautiful dates.
